const fs = require('fs');
const path = require('path');

const params = $('Set Global Parameters').first().json;
const deckRaw = $input.first().json;
const deck = deckRaw.data || deckRaw;

const narConfig = deck.Prompts?.Narration || {};
const voiceMap = narConfig.VoiceMap || {};
const elementMap = narConfig.ElementMap || {};
const defaultVoice = narConfig.DefaultVoice || 'tara';
const defaultElement = narConfig.DefaultElement || 'none';

const narSamplers = deck.Samplers?.Narration || {};
const narModels = deck.Models || {};

const deckDir = deck.Assets.Directory;
const narrationDir = deck.Assets.NarrationDirectory || path.join(deckDir, 'Narration');

if (!fs.existsSync(deckDir)) {
  throw new Error(
    '[Build Narration Job List] Deck directory not found: ' + deckDir +
    '\nCheck that deck.Assets.Directory is correct in Deck.json'
  );
}

fs.mkdirSync(narrationDir, { recursive: true });

const jobs = [];
let skipped = 0;

for (const cardRef of deck.Cards || []) {
  const cardJsonPath = path.join(deckDir, cardRef.File);

  if (!fs.existsSync(cardJsonPath)) {
    console.warn('[Build Narration Job List] Missing card JSON: ' + cardJsonPath);
    continue;
  }

  const cardData = JSON.parse(fs.readFileSync(cardJsonPath, 'utf8'));
  const cardMeta = cardData['data.Cards'];
  if (!cardMeta) continue;

  const cardName = cardMeta.Card;

  for (const record of cardMeta.records || []) {
    const orientation = record.Orientation;
    const narAsset = record.Assets?.Narration;
    if (!narAsset) continue;

    const outputPath = path.join(narrationDir, narAsset);

    // Insertable audio: skip if file already exists
    if (fs.existsSync(outputPath)) {
      console.warn('[Build Narration Job List] Skipping existing: ' + narAsset);
      skipped++;
      continue;
    }

    const narPrompts = record.Prompts?.Narration || {};

    // Map voice descriptor to Orpheus voice name
    const voiceDescriptor = narPrompts.Voice || '';
    const orpheusVoice = voiceMap[voiceDescriptor] || defaultVoice;

    // Map tone to Orpheus emotional element
    const toneDescriptor = narPrompts.Tone || '';
    const orpheusElement = elementMap[toneDescriptor] || defaultElement;

    // Assemble narration script from structured card fields
    const scriptParts = [
      `${cardName}, ${orientation} position.`,
      record.Description || '',
      record.Advice ? `Advice: ${record.Advice}` : null,
      record.Affirmation ? record.Affirmation.replace(/\n/g, ' ') : null
    ].filter(Boolean);

    const script = scriptParts.join(' ').trim();

    // ComfyUI output prefix (inside narration/ subfolder of output dir)
    const outputPrefix = 'narration/' + path.basename(narAsset, '.mp3');

    jobs.push({
      CardName: cardName,
      CardFile: cardRef.File,
      Orientation: orientation,
      Script: script,
      OrpheusVoice: orpheusVoice,
      OrpheusElement: orpheusElement,
      ElementPosition: orpheusElement !== 'none' ? 'append' : 'none',
      OutputPath: outputPath,
      OutputPrefix: outputPrefix,
      NarAsset: narAsset,
      // Engine parameters from Deck.json
      OrpheusModelPath: narModels.NarrationTTS || 'canopylabs/orpheus-3b-0.1-ft',
      SnacModelPath: narModels.NarrationSNAC || 'hubertsiuzdak/snac_24khz',
      Temperature: narSamplers.Temperature || 0.6,
      TopP: narSamplers.TopP || 0.95,
      RepetitionPenalty: narSamplers.RepetitionPenalty || 1.1,
      MaxNewTokens: narSamplers.MaxNewTokens || 2700,
      Quality: narSamplers.Quality || '128k',
      // n8n parameters
      ComfyUIAPI: params.ComfyUIAPI || 'http://127.0.0.1:8188',
      ComfyUIOutputDir: params.ComfyUIOutputDir || 'D:/ComfyUI_windows_portable/ComfyUI/output'
    });
  }
}

if (jobs.length === 0 && skipped === 0) {
  throw new Error(
    '[Build Narration Job List] No jobs created.\n' +
    'Check: deck.Cards is populated, card JSON files exist, ' +
    'and deck.Assets.NarrationDirectory is set in Deck.json.'
  );
}

if (jobs.length === 0) {
  throw new Error(
    '[Build Narration Job List] All ' + skipped + ' narration files already exist. ' +
    'Delete files from ' + narrationDir + ' to regenerate.'
  );
}

console.log(`[Build Narration Job List] Created ${jobs.length} jobs (${skipped} already exist, skipped)`);
return jobs.map(j => ({ json: j }));

const axios = require('axios');
const fs = require('fs');
const path = require('path');

const allJobs = $input.all().map(item => item.json);
const sleep = ms => new Promise(r => setTimeout(r, ms));

const results = [];
const errors = [];

for (const job of allJobs) {
  const comfyAPI = job.ComfyUIAPI;
  const comfyOutputDir = job.ComfyUIOutputDir;

  const prompt = {
    "1": {
      "class_type": "OrpheusModelLoader",
      "inputs": {
        "snac_model_path": job.SnacModelPath,
        "orpheus_model_path": job.OrpheusModelPath
      }
    },
    "2": {
      "class_type": "OrpheusGenerate",
      "inputs": {
        "model": ["1", 0],
        "text": job.Script,
        "voice": job.OrpheusVoice,
        "element": job.OrpheusElement,
        "element_position": job.ElementPosition,
        "temperature": job.Temperature,
        "top_p": job.TopP,
        "repetition_penalty": job.RepetitionPenalty,
        "max_new_tokens": job.MaxNewTokens
      }
    },
    "3": {
      "class_type": "SaveAudioMP3",
      "inputs": {
        "audio": ["2", 0],
        "filename_prefix": job.OutputPrefix,
        "quality": job.Quality
      }
    }
  };

  console.log(`[Narration] Generating: ${job.CardName} (${job.Orientation}) → ${job.NarAsset}`);

  // Submit to ComfyUI
  let promptId;
  try {
    const submitRes = await axios.post(comfyAPI + '/prompt', { prompt });
    promptId = submitRes.data.prompt_id;
  } catch (e) {
    const msg = 'Submit failed: ' + (e.response?.data ? JSON.stringify(e.response.data) : e.message);
    errors.push({ ...job, error: msg });
    console.warn(`[Narration] ${msg}`);
    continue;
  }

  // Poll until done (Orpheus 3B generates ~30-120s per card at 6GB VRAM)
  // 240 attempts × 5s = 20 minutes max per card
  let done = false;
  let audioInfo = null;
  let comfyError = null;

  for (let attempt = 0; attempt < 240 && !done && !comfyError; attempt++) {
    await sleep(5000);
    try {
      const historyRes = await axios.get(comfyAPI + '/history/' + promptId);
      const entry = historyRes.data[promptId];
      if (entry?.outputs?.['3']?.audio?.length > 0) {
        audioInfo = entry.outputs['3'].audio[0];
        done = true;
      } else if (entry?.status?.status_str === 'error') {
        // ComfyUI execution errored — find the message and bail immediately
        const msgs = entry?.status?.messages || [];
        const errMsg = msgs.find(m => m[0] === 'execution_error');
        comfyError = errMsg ? errMsg[1].exception_message : 'ComfyUI execution error (no detail)';
      } else if (entry?.status?.completed === true && !entry?.outputs?.['3']) {
        // Completed but no audio output (node_errors or silent fail)
        const nodeErrs = entry?.status?.messages?.filter(m => m[0] === 'execution_error') || [];
        comfyError = nodeErrs.length ? nodeErrs[0][1].exception_message : 'Completed with no audio output';
      }
    } catch (e) {
      // Transient poll error - keep retrying
    }
  }

  if (comfyError) {
    errors.push({ ...job, error: 'ComfyUI error: ' + comfyError.slice(0, 200) });
    console.warn(`[Narration] ComfyUI error for ${job.CardName} ${job.Orientation}: ${comfyError.slice(0, 150)}`);
    continue;
  }

  if (!done) {
    errors.push({ ...job, error: 'Timeout after 20 minutes' });
    console.warn(`[Narration] Timeout: ${job.CardName} ${job.Orientation}`);
    continue;
  }

  // Copy from ComfyUI output/ to target narration directory
  const subfolder = audioInfo.subfolder || '';
  const srcPath = path.join(comfyOutputDir, subfolder, audioInfo.filename);

  try {
    fs.mkdirSync(path.dirname(job.OutputPath), { recursive: true });
    fs.copyFileSync(srcPath, job.OutputPath);
    console.log(`[Narration] ✓ Saved: ${job.NarAsset}`);
    results.push({ ...job, SavedFilename: audioInfo.filename });
  } catch (e) {
    errors.push({ ...job, error: 'Copy failed: ' + e.message });
    console.warn(`[Narration] Copy failed for ${job.NarAsset}: ${e.message}`);
  }
}

if (results.length === 0 && errors.length > 0) {
  throw new Error(`[Narration] All ${errors.length} jobs failed. First error: ${errors[0].error}`);
}

if (errors.length > 0) {
  console.warn(`[Narration] Completed with ${errors.length} errors (${results.length} succeeded).`);
}

return [...results, ...errors].map(r => ({ json: r }));

const all = $input.all().map(i => i.json);
const succeeded = all.filter(j => !j.error);
const failed = all.filter(j => j.error);

console.log(`[Report] Narration generation complete: ${succeeded.length} succeeded, ${failed.length} failed`);

if (failed.length > 0) {
  console.warn('[Report] Failed jobs:');
  for (const f of failed) {
    console.warn(`  ${f.CardName} (${f.Orientation}): ${f.error}`);
  }
}

return [{
  json: {
    succeeded: succeeded.length,
    failed: failed.length,
    total: all.length,
    failedJobs: failed.map(f => ({
      card: f.CardName,
      orientation: f.Orientation,
      error: f.error
    }))
  }
}];
